import { useQuery } from "@tanstack/react-query";
import {
	Clock,
	DollarSign,
	FolderKanban,
	TrendingUp,
	Users,
	Zap,
} from "lucide-react";
import { useNavigate } from "react-router-dom";
import { AnalyticsCard } from "@/components/analytics/AnalyticsCard";
import { DatePicker } from "@/components/analytics/DatePicker";
import { PageHeader } from "@/components/analytics/PageHeader";
import { StatCard } from "@/components/analytics/StatCard";
import { ProjectTrendChart } from "@/components/charts/ProjectTrendChart";
import { useDateRange } from "@/contexts/DateRangeContext";
import { encodeProjectPath } from "@/lib/format";
import { orpc } from "@/lib/orpc";

export function ProjectsListPage() {
	const navigate = useNavigate();
	const { startDate, endDate, setStartDate, setEndDate, calculateDays } =
		useDateRange();
	const days = calculateDays();

	const { data: projects, isLoading } = useQuery(
		orpc.analytics.projects.investment.queryOptions({ input: { days } }),
	);

	const { data: trendData } = useQuery(
		orpc.analytics.projects.trends.queryOptions({ input: { days } }),
	);

	const totalProjects = projects?.length ?? 0;
	const totalSessions = projects?.reduce((sum, p) => sum + p.sessions, 0) ?? 0;
	const totalHours =
		(projects?.reduce((sum, p) => sum + p.total_duration_min, 0) ?? 0) / 60;
	const totalCost = projects?.reduce((sum, p) => sum + (p.cost || 0), 0) ?? 0;
	const totalTokens =
		projects?.reduce((sum, p) => sum + (p.total_tokens || 0), 0) ?? 0;
	const avgUsersPerProject =
		totalProjects > 0
			? (
					(projects?.reduce((sum, p) => sum + p.unique_users, 0) ?? 0) /
					totalProjects
				).toFixed(1)
			: "0";

	const formatTokens = (tokens: number) => {
		if (tokens >= 1_000_000) return `${(tokens / 1_000_000).toFixed(1)}M`;
		if (tokens >= 1_000) return `${(tokens / 1_000).toFixed(1)}K`;
		return tokens.toString();
	};

	if (isLoading) {
		return (
			<div className="px-8 py-6">
				<PageHeader
					title="Projects"
					description="Analyze project activity and team investment"
					actions={
						<DatePicker
							startDate={startDate}
							endDate={endDate}
							onStartDateChange={setStartDate}
							onEndDateChange={setEndDate}
						/>
					}
				/>
				<AnalyticsCard>
					<p className="text-center text-muted">Loading project metrics...</p>
				</AnalyticsCard>
			</div>
		);
	}

	return (
		<div className="px-8 py-6">
			<PageHeader
				title="Projects"
				description="Analyze project activity and team investment"
				actions={
					<DatePicker
						startDate={startDate}
						endDate={endDate}
						onStartDateChange={setStartDate}
						onEndDateChange={setEndDate}
					/>
				}
			/>

			<div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-6 gap-6 mb-8">
				<StatCard
					title="Active Projects"
					value={totalProjects}
					icon={FolderKanban}
					iconColor="text-blue-600"
				/>
				<StatCard
					title="Total Sessions"
					value={totalSessions.toLocaleString()}
					icon={TrendingUp}
					iconColor="text-green-600"
				/>
				<StatCard
					title="Total Time"
					value={totalHours.toFixed(0)}
					icon={Clock}
					iconColor="text-purple-600"
				/>
				<StatCard
					title="Total Tokens"
					value={formatTokens(totalTokens)}
					icon={Zap}
					iconColor="text-amber-600"
				/>
				<StatCard
					title="Total Cost"
					value={`$${totalCost.toFixed(2)}`}
					icon={DollarSign}
					iconColor="text-emerald-600"
				/>
				<StatCard
					title="Avg Users"
					value={avgUsersPerProject}
					icon={Users}
					iconColor="text-indigo-600"
				/>
			</div>

			{trendData && trendData.length > 0 && (
				<AnalyticsCard className="mb-8">
					<h2 className="text-xl font-bold text-heading mb-4">
						Project Trends
					</h2>
					<p className="text-sm text-muted mb-6">
						Activity metrics over time split by project (top 10)
					</p>
					<ProjectTrendChart data={trendData} maxProjects={10} />
				</AnalyticsCard>
			)}

			<AnalyticsCard>
				<h2 className="text-xl font-bold text-heading mb-4">Project Details</h2>
				{projects && projects.length > 0 ? (
					<div className="overflow-x-auto">
						<table className="min-w-full divide-y divide-border">
							<thead className="bg-surface">
								<tr>
									<th className="px-6 py-3 text-left text-xs font-medium text-muted uppercase tracking-wider">
										Project
									</th>
									<th className="px-6 py-3 text-left text-xs font-medium text-muted uppercase tracking-wider">
										Sessions
									</th>
									<th className="px-6 py-3 text-left text-xs font-medium text-muted uppercase tracking-wider">
										Time
									</th>
									<th className="px-6 py-3 text-left text-xs font-medium text-muted uppercase tracking-wider">
										Tokens
									</th>
									<th className="px-6 py-3 text-left text-xs font-medium text-muted uppercase tracking-wider">
										Success Rate
									</th>
									<th className="px-6 py-3 text-left text-xs font-medium text-muted uppercase tracking-wider">
										Cost
									</th>
									<th className="px-6 py-3 text-left text-xs font-medium text-muted uppercase tracking-wider">
										Trend
									</th>
								</tr>
							</thead>
							<tbody className="bg-input divide-y divide-border">
								{projects.map((project, index) => {
									const encodedPath = encodeProjectPath(project.project_path);
									const successRate = project.success_rate || 0;
									const successRateColor =
										successRate >= 70
											? "text-status-success-icon"
											: successRate >= 50
												? "text-status-warning-icon"
												: "text-status-error-icon";
									const trend = project.success_rate_trend || 0;
									const trendIconStr =
										trend > 0 ? "\u2191" : trend < 0 ? "\u2193" : "-";
									const trendColor =
										trend > 0
											? "text-status-success-icon"
											: trend < 0
												? "text-status-error-icon"
												: "text-muted";

									return (
										<tr
											// biome-ignore lint/suspicious/noArrayIndexKey: static project list
											key={index}
											onClick={() =>
												navigate(`/dashboard/projects/${encodedPath}`)
											}
											className="hover:bg-hover cursor-pointer"
										>
											<td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-foreground">
												{project.project_path.split("/").pop()}
											</td>
											<td className="px-6 py-4 whitespace-nowrap text-sm text-muted">
												{project.sessions}
											</td>
											<td className="px-6 py-4 whitespace-nowrap text-sm text-muted">
												{(project.total_duration_min / 60).toFixed(1)}h
											</td>
											<td className="px-6 py-4 whitespace-nowrap text-sm text-muted">
												{formatTokens(project.total_tokens || 0)}
											</td>
											<td
												className={`px-6 py-4 whitespace-nowrap text-sm font-semibold ${successRateColor}`}
											>
												{successRate.toFixed(0)}%
											</td>
											<td className="px-6 py-4 whitespace-nowrap text-sm text-muted">
												${(project.cost || 0).toFixed(2)}
											</td>
											<td
												className={`px-6 py-4 whitespace-nowrap text-sm font-semibold ${trendColor}`}
											>
												{trendIconStr} {Math.abs(trend).toFixed(1)}%
											</td>
										</tr>
									);
								})}
							</tbody>
						</table>
					</div>
				) : (
					<p className="text-center text-muted py-8">
						No project data available
					</p>
				)}
			</AnalyticsCard>
		</div>
	);
}

import { useQuery } from "@tanstack/react-query";
import {
	Activity,
	ArrowDown,
	ArrowUp,
	Clock,
	Code,
	Minus,
	Users,
} from "lucide-react";
import { useMemo, useState } from "react";
import { useNavigate } from "react-router-dom";
import { AnalyticsCard } from "@/components/analytics/AnalyticsCard";
import { DatePicker } from "@/components/analytics/DatePicker";
import { PageHeader } from "@/components/analytics/PageHeader";
import { StatCard } from "@/components/analytics/StatCard";
import { DeveloperTrendChart } from "@/components/charts/DeveloperTrendChart";
import { useDateRange } from "@/contexts/DateRangeContext";
import { formatUsername } from "@/lib/format";
import { orpc } from "@/lib/orpc";

export function DevelopersListPage() {
	const navigate = useNavigate();
	const { startDate, endDate, setStartDate, setEndDate, calculateDays } =
		useDateRange();
	const days = calculateDays();

	const [sortBy, setSortBy] = useState<
		"sessions" | "tokens" | "last_active" | "success_rate"
	>("sessions");

	const { data: developers, isLoading } = useQuery(
		orpc.analytics.developers.list.queryOptions({ input: { days } }),
	);

	const { data: trendsData } = useQuery(
		orpc.analytics.developers.trends.queryOptions({ input: { days } }),
	);

	const { data: userMappings } = useQuery(
		orpc.analytics.users.mappings.queryOptions({ input: { days: 30 } }),
	);

	const userMap = useMemo(() => {
		const map = new Map<string, string>();
		if (userMappings) {
			for (const m of userMappings) {
				map.set(m.user_id, m.username);
			}
		}
		return map;
	}, [userMappings]);

	const userMapRecord = useMemo(() => Object.fromEntries(userMap), [userMap]);

	const sortedDevelopers = useMemo(() => {
		if (!developers) return [];
		return [...developers].sort((a, b) => {
			if (sortBy === "sessions") return b.total_sessions - a.total_sessions;
			if (sortBy === "tokens") return b.total_tokens - a.total_tokens;
			if (sortBy === "success_rate") return b.success_rate - a.success_rate;
			return (
				new Date(b.last_active_date).getTime() -
				new Date(a.last_active_date).getTime()
			);
		});
	}, [developers, sortBy]);

	const totalSessions =
		developers?.reduce((sum, d) => sum + d.total_sessions, 0) ?? 0;
	const totalTokens =
		developers?.reduce((sum, d) => sum + d.total_tokens, 0) ?? 0;
	const totalHours =
		(developers?.reduce((sum, d) => sum + d.total_duration_min, 0) ?? 0) / 60;

	if (isLoading) {
		return (
			<div className="px-8 py-6">
				<PageHeader
					title="Developers"
					description="Individual developer activity and metrics"
					actions={
						<DatePicker
							startDate={startDate}
							endDate={endDate}
							onStartDateChange={setStartDate}
							onEndDateChange={setEndDate}
						/>
					}
				/>
				<AnalyticsCard>
					<p className="text-center text-muted">Loading developers...</p>
				</AnalyticsCard>
			</div>
		);
	}

	return (
		<div className="px-8 py-6">
			<PageHeader
				title="Developers"
				description="Individual developer activity and metrics"
				actions={
					<DatePicker
						startDate={startDate}
						endDate={endDate}
						onStartDateChange={setStartDate}
						onEndDateChange={setEndDate}
					/>
				}
			/>

			{/* Summary Stats */}
			<div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
				<StatCard
					title="Total Developers"
					value={developers?.length ?? 0}
					icon={Users}
					iconColor="text-blue-600"
				/>
				<StatCard
					title="Total Sessions"
					value={totalSessions.toLocaleString()}
					icon={Activity}
					iconColor="text-green-600"
				/>
				<StatCard
					title="Total Tokens"
					value={`${(totalTokens / 1000000).toFixed(1)}M`}
					icon={Code}
					iconColor="text-purple-600"
				/>
				<StatCard
					title="Total Hours"
					value={totalHours.toFixed(0)}
					icon={Clock}
					iconColor="text-orange-600"
				/>
			</div>

			{/* Developers Table */}
			<AnalyticsCard>
				<div className="flex justify-between items-center mb-6">
					<h2 className="text-xl font-bold text-heading">Developer List</h2>
					<div className="flex gap-2">
						{(
							["sessions", "tokens", "success_rate", "last_active"] as const
						).map((key) => (
							<button
								type="button"
								key={key}
								onClick={() => setSortBy(key)}
								className={`px-3 py-1 text-sm rounded ${
									sortBy === key
										? "bg-accent text-accent-foreground"
										: "bg-surface text-subheading"
								}`}
							>
								{key === "sessions"
									? "Sessions"
									: key === "tokens"
										? "Tokens"
										: key === "success_rate"
											? "Success Rate"
											: "Last Active"}
							</button>
						))}
					</div>
				</div>

				<div className="overflow-x-auto">
					<table className="min-w-full divide-y divide-border">
						<thead className="bg-surface">
							<tr>
								<th className="px-6 py-3 text-left text-xs font-medium text-muted uppercase tracking-wider">
									Developer
								</th>
								<th className="px-6 py-3 text-left text-xs font-medium text-muted uppercase tracking-wider">
									Sessions
								</th>
								<th className="px-6 py-3 text-left text-xs font-medium text-muted uppercase tracking-wider">
									Active Days
								</th>
								<th className="px-6 py-3 text-left text-xs font-medium text-muted uppercase tracking-wider">
									Total Tokens
								</th>
								<th className="px-6 py-3 text-left text-xs font-medium text-muted uppercase tracking-wider">
									Success Rate
								</th>
								<th className="px-6 py-3 text-left text-xs font-medium text-muted uppercase tracking-wider">
									Cost
								</th>
								<th className="px-6 py-3 text-left text-xs font-medium text-muted uppercase tracking-wider">
									Trend
