354→									User
355→								</th>
356→								<th className="px-6 py-3 text-left text-xs font-medium text-muted uppercase tracking-wider">
357→									Project
358→								</th>
359→								<th className="px-6 py-3 text-left text-xs font-medium text-muted uppercase tracking-wider">
360→									Duration
361→								</th>
362→								<th className="px-6 py-3 text-left text-xs font-medium text-muted uppercase tracking-wider">
363→									Success Score
364→								</th>
365→								<th className="px-6 py-3 text-left text-xs font-medium text-muted uppercase tracking-wider">
366→									Cost
367→								</th>
368→							</tr>
369→						</thead>
370→						<tbody className="bg-input divide-y divide-border">
371→							{filteredSessions.map((session) => (
