381→											{session.session_id.slice(0, 8)}...
382→										</Link>
383→									</td>
384→									<td className="px-6 py-4 whitespace-nowrap text-sm text-foreground">
385→										{new Date(session.session_date).toLocaleDateString()}
386→										<br />
387→										<span className="text-xs text-muted">
388→											{new Date(session.session_date).toLocaleTimeString()}
389→										</span>
390→									</td>
391→									<td className="px-6 py-4 whitespace-nowrap text-sm text-subheading">
392→										{formatUsername(session.user_id, userMapRecord)}
393→									</td>
394→									<td className="px-6 py-4 text-sm text-foreground">
395→										<div
396→											className="max-w-xs truncate"
397→											title={session.project_path}
398→										>
399→											{session.project_path.split("/").pop() ||
400→												session.project_path}
401→										</div>
402→									</td>
403→									<td className="px-6 py-4 whitespace-nowrap text-sm text-foreground">
404→										{session.duration_min.toFixed(0)} min
405→									</td>
406→									<td className="px-6 py-4 whitespace-nowrap text-sm">
407→										<span
408→											className={`font-semibold ${
409→												session.success_score >= 70
410→													? "text-status-success-icon"
411→													: session.success_score >= 40
412→														? "text-status-warning-icon"
413→														: "text-status-error-icon"
414→											}`}
415→										>
416→											{session.success_score.toFixed(0)}
417→										</span>
418→										<span className="text-xs text-muted"> / 100</span>
419→									</td>
420→									<td className="px-6 py-4 whitespace-nowrap text-sm text-foreground font-mono">
421→										$
422→										{calculateCost(
423→											session.input_tokens,
424→											session.output_tokens,
425→										).toFixed(4)}
426→									</td>
427→								</tr>
428→							))}
