  1→import type { ErrorTrendDataPoint } from "@rudel/api-routes";
  2→import { useMemo } from "react";
  3→import {
  4→	Area,
  5→	AreaChart,
  6→	CartesianGrid,
  7→	Legend,
  8→	Line,
  9→	LineChart,
 10→	ResponsiveContainer,
 11→	Tooltip,
 12→	XAxis,
 13→	YAxis,
 14→} from "recharts";
 15→import { useChartTheme } from "@/hooks/useChartTheme";
 16→
 17→interface ErrorTrendChartProps {
 18→	data: ErrorTrendDataPoint[];
 19→	metric:
 20→		| "avg_errors_per_interaction"
 21→		| "avg_errors_per_session"
 22→		| "total_errors";
 23→	splitBy: "repository" | "user_id" | "model";
 24→	onMetricChange: (
 25→		metric:
 26→			| "avg_errors_per_interaction"
 27→			| "avg_errors_per_session"
 28→			| "total_errors",
 29→	) => void;
 30→	onSplitByChange: (splitBy: "repository" | "user_id" | "model") => void;
 31→	userMap?: Map<string, string>;
 32→}
 33→
 34→const COLORS = [
 35→	"#ef4444",
 36→	"#f59e0b",
 37→	"#10b981",
 38→	"#3b82f6",
 39→	"#8b5cf6",
 40→	"#ec4899",
 41→	"#06b6d4",
 42→	"#14b8a6",
 43→	"#f97316",
 44→	"#6366f1",
 45→];
 46→
 47→const METRIC_LABELS: Record<string, string> = {
 48→	avg_errors_per_interaction: "Avg Errors per Interaction",
 49→	avg_errors_per_session: "Avg Errors per Session",
 50→	total_errors: "Total Errors",
 51→};
 52→
 53→const SPLIT_LABELS: Record<string, string> = {
 54→	repository: "by Repository",
 55→	user_id: "by Developer",
 56→	model: "by Model",
 57→};
 58→
 59→export function ErrorTrendChart({
 60→	data,
 61→	metric,
 62→	splitBy,
 63→	onMetricChange,
 64→	onSplitByChange,
 65→	userMap,
 66→}: ErrorTrendChartProps) {
 67→	const { tooltipBg, tooltipBorder, gridStroke } = useChartTheme();
 68→
 69→	const seriesKeys = useMemo(() => {
 70→		if (data.length === 0) return [];
 71→		const keys = new Set<string>();
 72→		for (const item of data) {
 73→			keys.add(item.dimension);
 74→		}
 75→		return Array.from(keys).sort();
 76→	}, [data]);
 77→
 78→	const chartData = useMemo(() => {
 79→		if (data.length === 0) return [];
 80→
 81→		const allDates = Array.from(new Set(data.map((item) => item.date))).sort();
 82→		if (allDates.length === 0) return [];
 83→
 84→		const minDate = new Date(allDates[0]);
 85→		const maxDate = new Date(allDates[allDates.length - 1]);
 86→		const dateRange: string[] = [];
 87→
 88→		for (let d = new Date(minDate); d <= maxDate; d.setDate(d.getDate() + 1)) {
 89→			dateRange.push(d.toISOString().split("T")[0]);
 90→		}
 91→
 92→		const dateMap = new Map<string, Record<string, unknown>>();
 93→
 94→		for (const dateKey of dateRange) {
 95→			const dateData: Record<string, unknown> = {
 96→				date: dateKey,
 97→				displayDate: new Date(dateKey).toLocaleDateString("en-US", {
 98→					month: "short",
 99→					day: "numeric",
100→				}),
101→			};
102→			for (const key of seriesKeys) {
103→				dateData[key] = 0;
104→			}
105→			dateMap.set(dateKey, dateData);
106→		}
107→
108→		for (const item of data) {
109→			const dateKey = item.date;
110→			const dateData = dateMap.get(dateKey);
111→			if (dateData) {
112→				dateData[item.dimension] = item[metric];
113→			}
114→		}
115→
