  1→import { Check, ChevronDown, X } from "lucide-react";
  2→import { useEffect, useRef, useState } from "react";
  3→import { cn } from "../../lib/utils";
  4→
  5→interface MultiSelectProps {
  6→	options: string[];
  7→	selected: string[];
  8→	onChange: (selected: string[]) => void;
  9→	placeholder?: string;
 10→	className?: string;
 11→}
 12→
 13→export function MultiSelect({
 14→	options,
 15→	selected,
 16→	onChange,
 17→	placeholder = "Select items...",
 18→	className = "",
 19→}: MultiSelectProps) {
 20→	const [isOpen, setIsOpen] = useState(false);
 21→	const dropdownRef = useRef<HTMLDivElement>(null);
 22→
 23→	useEffect(() => {
 24→		function handleClickOutside(event: MouseEvent) {
 25→			if (
 26→				dropdownRef.current &&
 27→				!dropdownRef.current.contains(event.target as Node)
 28→			) {
 29→				setIsOpen(false);
 30→			}
 31→		}
 32→
 33→		document.addEventListener("mousedown", handleClickOutside);
 34→		return () => document.removeEventListener("mousedown", handleClickOutside);
 35→	}, []);
 36→
 37→	const toggleOption = (option: string) => {
 38→		if (selected.includes(option)) {
 39→			onChange(selected.filter((item) => item !== option));
 40→		} else {
 41→			onChange([...selected, option]);
 42→		}
 43→	};
 44→
 45→	const clearAll = (e: React.MouseEvent) => {
 46→		e.stopPropagation();
 47→		onChange([]);
 48→	};
 49→
 50→	const displayText =
 51→		selected.length === 0
 52→			? placeholder
 53→			: selected.length === 1
 54→				? selected[0]
 55→				: `${selected.length} selected`;
 56→
 57→	return (
 58→		<div ref={dropdownRef} className={cn("relative", className)}>
 59→			<button
 60→				type="button"
 61→				onClick={() => setIsOpen(!isOpen)}
 62→				className="w-full px-3 py-1.5 text-sm border border-border rounded-lg bg-input text-foreground focus:outline-none focus:ring-2 focus:ring-accent flex items-center justify-between gap-2"
 63→			>
 64→				<span className={cn("truncate", selected.length === 0 && "text-muted")}>
 65→					{selected.length > 0 && (
 66→						<Check className="w-3 h-3 inline mr-1 text-status-success-icon" />
 67→					)}
 68→					{displayText}
 69→				</span>
 70→				<div className="flex items-center gap-1">
 71→					{selected.length > 0 && (
 72→						<button
 73→							type="button"
 74→							onClick={clearAll}
 75→							className="p-0.5 hover:bg-hover rounded"
 76→							title="Clear all"
 77→						>
 78→							<X className="w-3 h-3 text-muted" />
 79→						</button>
 80→					)}
 81→					<ChevronDown
 82→						className={cn(
 83→							"w-4 h-4 text-muted transition-transform",
 84→							isOpen && "rotate-180",
 85→						)}
 86→					/>
 87→				</div>
 88→			</button>
 89→
 90→			{isOpen && (
 91→				<div className="absolute z-50 w-full mt-1 bg-input border border-border rounded-lg max-h-60 overflow-y-auto">
 92→					{options.length === 0 ? (
 93→						<div className="px-3 py-2 text-sm text-muted text-center">
 94→							No options available
 95→						</div>
 96→					) : (
 97→						options.map((option) => {
 98→							const isSelected = selected.includes(option);
 99→							return (
100→								<button
101→									key={option}
102→									type="button"
103→									onClick={() => toggleOption(option)}
104→									className={cn(
105→										"w-full px-3 py-2 text-sm text-left hover:bg-hover flex items-center gap-2",
106→										isSelected && "bg-accent-light",
107→									)}
108→								>
109→									<div
110→										className={cn(
111→											"w-4 h-4 border rounded flex items-center justify-center",
112→											isSelected ? "bg-accent border-accent" : "border-border",
