Read the file first, then rewrite it. The public interface (props) must stay identical.

Here's the refactored version to write:

```tsx
import { Check, ChevronDown, X } from "lucide-react";
import { useState } from "react";
import { Checkbox } from "@/components/ui/checkbox";
import {
	Popover,
	PopoverContent,
	PopoverTrigger,
} from "@/components/ui/popover";
import { cn } from "@/lib/utils";

interface MultiSelectProps {
	options: string[];
	selected: string[];
	onChange: (selected: string[]) => void;
	placeholder?: string;
	className?: string;
}

export function MultiSelect({
	options,
	selected,
	onChange,
	placeholder = "Select items...",
	className = "",
}: MultiSelectProps) {
	const [open, setOpen] = useState(false);

	const toggleOption = (option: string) => {
		if (selected.includes(option)) {
			onChange(selected.filter((item) => item !== option));
		} else {
			onChange([...selected, option]);
		}
	};

	const clearAll = (e: React.MouseEvent) => {
		e.stopPropagation();
		onChange([]);
	};

	const displayText =
		selected.length === 0
			? placeholder
			: selected.length === 1
				? selected[0]
				: `${selected.length} selected`;

	return (
		<Popover open={open} onOpenChange={setOpen}>
			<PopoverTrigger asChild>
				<button
					type="button"
					className={cn(
						"w-full px-3 py-1.5 text-sm border border-border rounded-lg bg-input text-foreground focus:outline-none focus:ring-2 focus:ring-accent flex items-center justify-between gap-2",
						className,
					)}
				>
					<span
						className={cn("truncate", selected.length === 0 && "text-muted")}
					>
						{selected.length > 0 && (
							<Check className="w-3 h-3 inline mr-1 text-status-success-icon" />
						)}
						{displayText}
					</span>
					<div className="flex items-center gap-1">
						{selected.length > 0 && (
							<button
								type="button"
								onClick={clearAll}
								className="p-0.5 hover:bg-hover rounded"
								title="Clear all"
							>
								<X className="w-3 h-3 text-muted" />
							</button>
						)}
						<ChevronDown
							className={cn(
								"w-4 h-4 text-muted transition-transform",
								open && "rotate-180",
							)}
						/>
					</div>
				</button>
			</PopoverTrigger>
			<PopoverContent
				className="w-[var(--radix-popover-trigger-width)] p-0"
				align="start"
			>
				{options.length === 0 ? (
					<div className="px-3 py-2 text-sm text-muted text-center">
						No options available
					</div>
				) : (
					<div className="max-h-60 overflow-y-auto">
						{options.map((option) => {
							const isSelected = selected.includes(option);
							return (
								<button
									key={option}
									type="button"
									onClick={() => toggleOption(option)}
									className={cn(
										"w-full px-3 py-2 text-sm text-left hover:bg-hover flex items-center gap-2",
										isSelected && "bg-accent-light",
									)}
								>
									<Checkbox
										checked={isSelected}
										tabIndex={-1}
										className="pointer-events-none"
									/>
									<span
										className={cn(
											isSelected
												? "font-medium text-accent-text"
												: "text-foreground",
										)}
									>
										{option}
									</span>
								</button>
							);
						})}
					</div>
				)}
			</PopoverContent>
		</Popover>
	);
}
```

Key changes:
- Removed `useEffect`, `useRef` - no more manual click-outside detection
- Used Popover for the dropdown container (handles click-outside + Escape automatically)
- Used Checkbox for option items (replaces hand-rolled checkbox div)
- Public interface stays identical

