141→						<div className="inline-block h-10 w-10 animate-spin rounded-full border-4 border-solid border-accent border-r-transparent mb-4" />

  1→import { useQuery } from "@tanstack/react-query";
  2→import {
  3→	Clock,
  4→	DollarSign,
  5→	FolderKanban,
  6→	TrendingUp,
  7→	Users,
  8→	Zap,
  9→} from "lucide-react";
 10→import { useNavigate } from "react-router-dom";
 11→import { AnalyticsCard } from "@/components/analytics/AnalyticsCard";
 12→import { DatePicker } from "@/components/analytics/DatePicker";
 13→import { PageHeader } from "@/components/analytics/PageHeader";
 14→import { StatCard } from "@/components/analytics/StatCard";
 15→import { ProjectTrendChart } from "@/components/charts/ProjectTrendChart";
 16→import { useDateRange } from "@/contexts/DateRangeContext";
 17→import { encodeProjectPath } from "@/lib/format";
 18→import { orpc } from "@/lib/orpc";
 19→
 20→export function ProjectsListPage() {
 21→	const navigate = useNavigate();
 22→	const { startDate, endDate, setStartDate, setEndDate, calculateDays } =
 23→		useDateRange();
 24→	const days = calculateDays();
 25→
 26→	const { data: projects, isLoading } = useQuery(
 27→		orpc.analytics.projects.investment.queryOptions({ input: { days } }),
 28→	);
 29→
 30→	const { data: trendData } = useQuery(
 31→		orpc.analytics.projects.trends.queryOptions({ input: { days } }),
 32→	);
 33→
 34→	const totalProjects = projects?.length ?? 0;
 35→	const totalSessions = projects?.reduce((sum, p) => sum + p.sessions, 0) ?? 0;
 36→	const totalHours =
 37→		(projects?.reduce((sum, p) => sum + p.total_duration_min, 0) ?? 0) / 60;
 38→	const totalCost = projects?.reduce((sum, p) => sum + (p.cost || 0), 0) ?? 0;
 39→	const totalTokens =
 40→		projects?.reduce((sum, p) => sum + (p.total_tokens || 0), 0) ?? 0;
 41→	const avgUsersPerProject =
 42→		totalProjects > 0
 43→			? (
 44→					(projects?.reduce((sum, p) => sum + p.unique_users, 0) ?? 0) /
 45→					totalProjects
 46→				).toFixed(1)
 47→			: "0";
 48→
 49→	const formatTokens = (tokens: number) => {
 50→		if (tokens >= 1_000_000) return `${(tokens / 1_000_000).toFixed(1)}M`;
 51→		if (tokens >= 1_000) return `${(tokens / 1_000).toFixed(1)}K`;
 52→		return tokens.toString();
 53→	};
 54→
 55→	if (isLoading) {
 56→		return (
 57→			<div className="px-8 py-6">
 58→				<PageHeader
 59→					title="Projects"
 60→					description="Analyze project activity and team investment"
 61→					actions={
 62→						<DatePicker
 63→							startDate={startDate}
 64→							endDate={endDate}
 65→							onStartDateChange={setStartDate}
 66→							onEndDateChange={setEndDate}
 67→						/>
 68→					}
 69→				/>
 70→				<AnalyticsCard>
 71→					<p className="text-center text-muted">Loading project metrics...</p>
 72→				</AnalyticsCard>
 73→			</div>
 74→		);
 75→	}
 76→
 77→	return (
 78→		<div className="px-8 py-6">
 79→			<PageHeader
 80→				title="Projects"
 81→				description="Analyze project activity and team investment"
 82→				actions={
 83→					<DatePicker
 84→						startDate={startDate}
 85→						endDate={endDate}
 86→						onStartDateChange={setStartDate}
 87→						onEndDateChange={setEndDate}
 88→					/>
 89→				}
 90→			/>
 91→
 92→			<div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-6 gap-6 mb-8">
 93→				<StatCard
 94→					title="Active Projects"
 95→					value={totalProjects}
 96→					icon={FolderKanban}
 97→					iconColor="text-blue-600"
 98→				/>
 99→				<StatCard
100→					title="Total Sessions"
101→					value={totalSessions.toLocaleString()}
102→					icon={TrendingUp}
103→					iconColor="text-green-600"
104→				/>
105→				<StatCard
106→					title="Total Time"
107→					value={totalHours.toFixed(0)}
108→					icon={Clock}
109→					iconColor="text-purple-600"
110→				/>
111→				<StatCard
112→					title="Total Tokens"
113→					value={formatTokens(totalTokens)}
114→					icon={Zap}
115→					iconColor="text-amber-600"
116→				/>
