  1→import { useQuery } from "@tanstack/react-query";
  2→import {
  3→	Clock,
  4→	DollarSign,
  5→	FolderKanban,
  6→	TrendingUp,
  7→	Users,
  8→	Zap,
  9→} from "lucide-react";
 10→import { useNavigate } from "react-router-dom";
 11→import { AnalyticsCard } from "@/components/analytics/AnalyticsCard";
 12→import {
 13→	Table,
 14→	TableBody,
 15→	TableCell,
 16→	TableHead,
 17→	TableHeader,
 18→	TableRow,
 19→} from "@/components/ui/table";
 20→import { DatePicker } from "@/components/analytics/DatePicker";
 21→import { PageHeader } from "@/components/analytics/PageHeader";
 22→import { StatCard } from "@/components/analytics/StatCard";
 23→import { ProjectTrendChart } from "@/components/charts/ProjectTrendChart";
 24→import { useDateRange } from "@/contexts/DateRangeContext";
 25→import { encodeProjectPath } from "@/lib/format";
 26→import { orpc } from "@/lib/orpc";
 27→
 28→export function ProjectsListPage() {
 29→	const navigate = useNavigate();
 30→	const { startDate, endDate, setStartDate, setEndDate, calculateDays } =
 31→		useDateRange();
 32→	const days = calculateDays();
 33→
 34→	const { data: projects, isLoading } = useQuery(
 35→		orpc.analytics.projects.investment.queryOptions({ input: { days } }),
 36→	);
 37→
 38→	const { data: trendData } = useQuery(
 39→		orpc.analytics.projects.trends.queryOptions({ input: { days } }),
 40→	);
 41→
 42→	const totalProjects = projects?.length ?? 0;
 43→	const totalSessions = projects?.reduce((sum, p) => sum + p.sessions, 0) ?? 0;
 44→	const totalHours =
 45→		(projects?.reduce((sum, p) => sum + p.total_duration_min, 0) ?? 0) / 60;
 46→	const totalCost = projects?.reduce((sum, p) => sum + (p.cost || 0), 0) ?? 0;
 47→	const totalTokens =
 48→		projects?.reduce((sum, p) => sum + (p.total_tokens || 0), 0) ?? 0;
 49→	const avgUsersPerProject =
 50→		totalProjects > 0
 51→			? (
 52→					(projects?.reduce((sum, p) => sum + p.unique_users, 0) ?? 0) /
 53→					totalProjects
 54→				).toFixed(1)
 55→			: "0";
 56→
 57→	const formatTokens = (tokens: number) => {
 58→		if (tokens >= 1_000_000) return `${(tokens / 1_000_000).toFixed(1)}M`;
 59→		if (tokens >= 1_000) return `${(tokens / 1_000).toFixed(1)}K`;
 60→		return tokens.toString();
 61→	};
 62→
 63→	if (isLoading) {
 64→		return (
 65→			<div className="px-8 py-6">
 66→				<PageHeader
 67→					title="Projects"
 68→					description="Analyze project activity and team investment"
 69→					actions={
 70→						<DatePicker
 71→							startDate={startDate}
 72→							endDate={endDate}
 73→							onStartDateChange={setStartDate}
 74→							onEndDateChange={setEndDate}
 75→						/>
 76→					}
 77→				/>
 78→				<AnalyticsCard>
 79→					<p className="text-center text-muted">Loading project metrics...</p>
 80→				</AnalyticsCard>
 81→			</div>
 82→		);
 83→	}
 84→
 85→	return (
 86→		<div className="px-8 py-6">
 87→			<PageHeader
 88→				title="Projects"
 89→				description="Analyze project activity and team investment"
 90→				actions={
 91→					<DatePicker
 92→						startDate={startDate}
 93→						endDate={endDate}
 94→						onStartDateChange={setStartDate}
 95→						onEndDateChange={setEndDate}
 96→					/>
 97→				}
 98→			/>
 99→
100→			<div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-6 gap-6 mb-8">
101→				<StatCard
102→					title="Active Projects"
103→					value={totalProjects}
104→					icon={FolderKanban}
105→					iconColor="text-blue-600"
106→				/>
107→				<StatCard
108→					title="Total Sessions"
109→					value={totalSessions.toLocaleString()}
110→					icon={TrendingUp}
111→					iconColor="text-green-600"
112→				/>
113→				<StatCard
114→					title="Total Time"
115→					value={totalHours.toFixed(0)}
116→					icon={Clock}
117→					iconColor="text-purple-600"
118→				/>
119→				<StatCard
120→					title="Total Tokens"
121→					value={formatTokens(totalTokens)}
122→					icon={Zap}
123→					iconColor="text-amber-600"
124→				/>
125→				<StatCard
126→					title="Total Cost"
127→					value={`$${totalCost.toFixed(2)}`}
128→					icon={DollarSign}
129→					iconColor="text-emerald-600"
130→				/>
131→				<StatCard
132→					title="Avg Users"
133→					value={avgUsersPerProject}
134→					icon={Users}
135→					iconColor="text-indigo-600"
136→				/>
137→			</div>
138→
139→			{trendData && trendData.length > 0 && (
140→				<AnalyticsCard className="mb-8">
141→					<h2 className="text-xl font-bold text-heading mb-4">
142→						Project Trends
143→					</h2>
144→					<p className="text-sm text-muted mb-6">
145→						Activity metrics over time split by project (top 10)
146→					</p>
147→					<ProjectTrendChart data={trendData} maxProjects={10} />
148→				</AnalyticsCard>
149→			)}
150→
151→			<AnalyticsCard>
152→				<h2 className="text-xl font-bold text-heading mb-4">Project Details</h2>
153→				{projects && projects.length > 0 ? (
154→					<Table>
155→						<TableHeader className="bg-surface">
156→							<TableRow>
157→								<TableHead className="px-6 py-3 text-xs text-muted uppercase tracking-wider">
158→									Project
159→								</TableHead>
160→								<TableHead className="px-6 py-3 text-xs text-muted uppercase tracking-wider">
161→									Sessions
162→								</TableHead>
163→								<TableHead className="px-6 py-3 text-xs text-muted uppercase tracking-wider">
164→									Time
165→								</TableHead>
166→								<TableHead className="px-6 py-3 text-xs text-muted uppercase tracking-wider">
167→									Tokens
168→								</TableHead>
169→								<TableHead className="px-6 py-3 text-xs text-muted uppercase tracking-wider">
170→									Success Rate
171→								</TableHead>
172→								<TableHead className="px-6 py-3 text-xs text-muted uppercase tracking-wider">
173→									Cost
174→								</TableHead>
175→								<TableHead className="px-6 py-3 text-xs text-muted uppercase tracking-wider">
176→									Trend
177→								</TableHead>
178→							</TableRow>
179→						</TableHeader>
180→						<TableBody className="bg-input">
181→							{projects.map((project, index) => {
182→								const encodedPath = encodeProjectPath(project.project_path);
183→								const successRate = project.success_rate || 0;
184→								const successRateColor =
185→									successRate >= 70
186→										? "text-status-success-icon"
187→										: successRate >= 50
188→											? "text-status-warning-icon"
189→											: "text-status-error-icon";
190→								const trend = project.success_rate_trend || 0;
191→								const trendIconStr =
192→									trend > 0 ? "\u2191" : trend < 0 ? "\u2193" : "-";
193→								const trendColor =
194→									trend > 0
195→										? "text-status-success-icon"
196→										: trend < 0
197→											? "text-status-error-icon"
198→											: "text-muted";
199→
200→								return (
201→									<TableRow
202→										// biome-ignore lint/suspicious/noArrayIndexKey: static project list
203→										key={index}
204→										onClick={() =>
205→											navigate(`/dashboard/projects/${encodedPath}`)
206→										}
207→										className="hover:bg-hover cursor-pointer"
208→									>
209→										<TableCell className="px-6 py-4 text-sm font-medium text-foreground">
210→											{project.project_path.split("/").pop()}
211→										</TableCell>
212→										<TableCell className="px-6 py-4 text-sm text-muted">
213→											{project.sessions}
214→										</TableCell>
215→										<TableCell className="px-6 py-4 text-sm text-muted">
216→											{(project.total_duration_min / 60).toFixed(1)}h
217→										</TableCell>
218→										<TableCell className="px-6 py-4 text-sm text-muted">
219→											{formatTokens(project.total_tokens || 0)}
220→										</TableCell>
221→										<TableCell
222→											className={`px-6 py-4 text-sm font-semibold ${successRateColor}`}
223→										>
224→											{successRate.toFixed(0)}%
225→										</TableCell>
226→										<TableCell className="px-6 py-4 text-sm text-muted">
227→											${(project.cost || 0).toFixed(2)}
228→										</TableCell>
229→										<TableCell
230→											className={`px-6 py-4 text-sm font-semibold ${trendColor}`}
231→										>
232→											{trendIconStr} {Math.abs(trend).toFixed(1)}%
233→										</TableCell>
234→									</TableRow>
235→								);
236→							})}
237→						</TableBody>
238→					</Table>
239→				) : (
240→					<p className="text-center text-muted py-8">
241→						No project data available
242→					</p>
243→				)}
244→			</AnalyticsCard>
245→		</div>
246→	);
247→}
248→

