  1→import {
  2→	Building2,
  3→	Check,
  4→	Copy,
  5→	Loader2,
  6→	Mail,
  7→	Plus,
  8→	Trash2,
  9→	UserPlus,
 10→	X,
 11→} from "lucide-react";
 12→import { useEffect, useState } from "react";
 13→import { Link } from "react-router-dom";
 14→import { AnalyticsCard } from "../../components/analytics/AnalyticsCard";
 15→import { PageHeader } from "../../components/analytics/PageHeader";
 16→import { Badge } from "../../components/ui/badge";
 17→import { Button } from "../../components/ui/button";
 18→import { Input } from "../../components/ui/input";
 19→import { useOrganization } from "../../contexts/OrganizationContext";
 20→import { authClient } from "../../lib/auth-client";
 21→
 22→interface FullOrg {
 23→	id: string;
 24→	name: string;
 25→	slug: string;
 26→	members: readonly {
 27→		id: string;
 28→		userId: string;
 29→		role: string;
 30→		user: { id: string; name: string; email: string; image: string | null };
 31→	}[];
 32→	invitations: readonly {
 33→		id: string;
 34→		email: string;
 35→		role: string | null;
 36→		status: string;
 37→	}[];
 38→}
 39→
 40→export function OrganizationPage() {
 41→	const { activeOrg } = useOrganization();
 42→	const [fullOrg, setFullOrg] = useState<FullOrg | null>(null);
 43→	const [loading, setLoading] = useState(true);
 44→	const [inviteEmail, setInviteEmail] = useState("");
 45→	const [inviteRole, setInviteRole] = useState("member");
 46→	const [inviting, setInviting] = useState(false);
 47→	const [inviteLink, setInviteLink] = useState<string | null>(null);
 48→	const [copied, setCopied] = useState(false);
 49→
 50→	const fetchOrg = async () => {
 51→		if (!activeOrg) return;
 52→		setLoading(true);
 53→		const res = await authClient.organization.getFullOrganization({
 54→			query: { organizationId: activeOrg.id },
 55→		});
 56→		if (res.data) {
 57→			setFullOrg(res.data as unknown as FullOrg);
 58→		}
 59→		setLoading(false);
 60→	};
 61→
 62→	// biome-ignore lint/correctness/useExhaustiveDependencies: refetch when org changes
 63→	useEffect(() => {
 64→		fetchOrg();
 65→	}, [activeOrg?.id]);
 66→
 67→	const handleInvite = async (e: React.FormEvent) => {
 68→		e.preventDefault();
 69→		if (!inviteEmail.trim()) return;
 70→		setInviting(true);
 71→		const res = await authClient.organization.inviteMember({
 72→			email: inviteEmail.trim(),
 73→			role: inviteRole as "member" | "admin",
 74→		});
 75→		if (res.data) {
 76→			const link = `${window.location.origin}/invitation/${res.data.id}`;
 77→			setInviteLink(link);
 78→			setInviteEmail("");
 79→			await fetchOrg();
 80→		}
 81→		setInviting(false);
 82→	};
 83→
 84→	const handleCopyLink = () => {
 85→		if (!inviteLink) return;
 86→		navigator.clipboard.writeText(inviteLink);
 87→		setCopied(true);
 88→		setTimeout(() => setCopied(false), 2000);
 89→	};
 90→
 91→	const handleRemoveMember = async (memberIdOrEmail: string) => {
 92→		await authClient.organization.removeMember({ memberIdOrEmail });
 93→		await fetchOrg();
 94→	};
 95→
 96→	const handleCancelInvitation = async (invitationId: string) => {
 97→		await authClient.organization.cancelInvitation({ invitationId });
 98→		await fetchOrg();
 99→	};
100→
101→	if (!activeOrg) {
102→		return (
103→			<div className="px-8 py-6">
104→				<p className="text-muted">No organization selected.</p>
105→			</div>
106→		);
107→	}
108→
109→	return (
110→		<div className="px-8 py-6">
111→			<PageHeader
112→				title="Organization"
113→				description={`Manage ${activeOrg.name}`}
114→				actions={
115→					<Link to="/dashboard/organization/new">
116→						<Button size="sm">
117→							<Plus className="h-4 w-4 mr-1" />
118→							Create Organization
119→						</Button>
120→					</Link>
121→				}
122→			/>
123→
124→			<div className="flex flex-col gap-6">
125→				{/* Organization Info */}
126→				<AnalyticsCard>
127→					<div className="flex items-center gap-4">
128→						<div className="flex h-12 w-12 items-center justify-center rounded-lg bg-hover">
129→							<Building2 className="h-6 w-6 text-muted" />
130→						</div>
131→						<div>
132→							<h2 className="text-lg font-semibold text-heading">
133→								{activeOrg.name}
134→							</h2>
135→							<p className="text-sm text-muted">/{activeOrg.slug}</p>
136→						</div>
137→					</div>
138→				</AnalyticsCard>
139→
140→				{/* Invite Members */}
141→				<AnalyticsCard>
142→					<h2 className="text-lg font-semibold text-heading mb-4">
143→						<UserPlus className="h-5 w-5 inline-block mr-2 -mt-0.5" />
144→						Invite Members
145→					</h2>
146→
147→					<form onSubmit={handleInvite} className="flex gap-2 mb-3">
148→						<Input
149→							type="email"
150→							placeholder="Email address"
151→							value={inviteEmail}
152→							onChange={(e) => {
153→								setInviteEmail(e.target.value);
154→								if (inviteLink) setInviteLink(null);
155→							}}
156→							className="flex-1"
157→						/>
158→						<select
159→							value={inviteRole}
160→							onChange={(e) => setInviteRole(e.target.value)}
161→							className="rounded-md border border-border bg-surface px-3 py-1.5 text-sm text-foreground"
162→						>
163→							<option value="member">Member</option>
164→							<option value="admin">Admin</option>
165→						</select>
166→						<Button
167→							type="submit"
168→							size="sm"
169→							disabled={inviting || !inviteEmail.trim()}
170→						>
171→							{inviting ? (
172→								<Loader2 className="h-4 w-4 animate-spin" />
173→							) : (
174→								<Mail className="h-4 w-4 mr-1" />
175→							)}
176→							Invite
177→						</Button>
178→					</form>
179→
180→					{inviteLink && (
181→						<div className="flex items-center gap-2 rounded-lg border border-border bg-hover/50 px-3 py-2 text-sm">
182→							<span className="flex-1 truncate text-muted">{inviteLink}</span>
183→							<Button variant="outline" size="xs" onClick={handleCopyLink}>
184→								{copied ? (
185→									<Check className="h-3.5 w-3.5 text-status-success-icon" />
186→								) : (
187→									<Copy className="h-3.5 w-3.5" />
188→								)}
189→							</Button>
190→							<Button
191→								variant="outline"
192→								size="xs"
193→								onClick={() => setInviteLink(null)}
194→							>
195→								<X className="h-3.5 w-3.5" />
196→							</Button>
197→						</div>
198→					)}
199→				</AnalyticsCard>
200→
201→				{/* Members */}
202→				<AnalyticsCard>
203→					<h2 className="text-lg font-semibold text-heading mb-4">Members</h2>
204→
205→					{loading ? (
206→						<p className="text-sm text-muted">Loading...</p>
207→					) : (
208→						<div className="flex flex-col gap-2">
209→							{fullOrg?.members.map((m) => (
210→								<div
211→									key={m.id}
212→									className="flex items-center justify-between rounded-lg border border-border px-4 py-3"
213→								>
214→									<div className="flex items-center gap-3">
215→										{m.user.image ? (
216→											<img
217→												src={m.user.image}
218→												alt=""
219→												className="h-8 w-8 rounded-full"
220→											/>
221→										) : (
222→											<div className="flex h-8 w-8 items-center justify-center rounded-full bg-hover text-xs font-medium text-muted">
223→												{m.user.name.charAt(0).toUpperCase()}
224→											</div>
225→										)}
226→										<div>
227→											<p className="text-sm font-medium text-foreground">
228→												{m.user.name}
229→											</p>
230→											<p className="text-xs text-muted">{m.user.email}</p>
231→										</div>
232→									</div>
233→									<div className="flex items-center gap-2">
234→										<Badge
235→											variant={m.role === "owner" ? "default" : "secondary"}
236→										>
237→											{m.role}
238→										</Badge>
239→										{m.role !== "owner" && (
240→											<Button
241→												variant="outline"
242→												size="xs"
243→												onClick={() => handleRemoveMember(m.id)}
244→											>
245→												<Trash2 className="h-3.5 w-3.5" />
246→											</Button>
247→										)}
248→									</div>
249→								</div>
250→							))}
251→						</div>
252→					)}
253→				</AnalyticsCard>
254→
255→				{/* Pending Invitations */}
256→				{fullOrg && fullOrg.invitations.length > 0 && (
257→					<AnalyticsCard>
258→						<h2 className="text-lg font-semibold text-heading mb-4">
259→							Pending Invitations
260→						</h2>
261→
262→						<div className="flex flex-col gap-2">
263→							{fullOrg.invitations
264→								.filter((inv) => inv.status === "pending")
265→								.map((inv) => (
266→									<div
267→										key={inv.id}
268→										className="flex items-center justify-between rounded-lg border border-border px-4 py-3"
269→									>
270→										<div className="flex items-center gap-3">
271→											<Mail className="h-4 w-4 text-muted" />
272→											<span className="text-sm text-foreground">
273→												{inv.email}
274→											</span>
275→											{inv.role && (
276→												<Badge variant="secondary">{inv.role}</Badge>
277→											)}
278→										</div>
279→										<Button
280→											variant="outline"
281→											size="xs"
282→											onClick={() => handleCancelInvitation(inv.id)}
283→										>
284→											<X className="h-3.5 w-3.5 mr-1" />
285→											Cancel
286→										</Button>
287→									</div>
288→								))}
289→						</div>
290→					</AnalyticsCard>
291→				)}
292→			</div>
293→		</div>
294→	);
295→}
