 17→interface ErrorTrendChartProps {
 18→	data: ErrorTrendDataPoint[];
 19→	metric:
 20→		| "avg_errors_per_interaction"
 21→		| "avg_errors_per_session"
 22→		| "total_errors";
 23→	splitBy: "repository" | "user_id" | "model";
 24→	onMetricChange: (
 25→		metric:
 26→			| "avg_errors_per_interaction"
 27→			| "avg_errors_per_session"
 28→			| "total_errors",
 29→	) => void;
 30→	onSplitByChange: (splitBy: "repository" | "user_id" | "model") => void;
 31→	userMap?: Map<string, string>;
 32→}
 33→
 34→const COLORS = [
 35→	"#ef4444",
 36→	"#f59e0b",
 37→	"#10b981",
 38→	"#3b82f6",
 39→	"#8b5cf6",
 40→	"#ec4899",
 41→	"#06b6d4",
 42→	"#14b8a6",
 43→	"#f97316",
 44→	"#6366f1",
 45→];
 46→
 47→const METRIC_LABELS: Record<string, string> = {
 48→	avg_errors_per_interaction: "Avg Errors per Interaction",
 49→	avg_errors_per_session: "Avg Errors per Session",
 50→	total_errors: "Total Errors",
 51→};
 52→
 53→const SPLIT_LABELS: Record<string, string> = {
 54→	repository: "by Repository",
 55→	user_id: "by Developer",
 56→	model: "by Model",
 57→};
 58→
 59→export function ErrorTrendChart({
 60→	data,
 61→	metric,
 62→	splitBy,
 63→	onMetricChange,
 64→	onSplitByChange,
 65→	userMap,
 66→}: ErrorTrendChartProps) {
 67→	const { tooltipBg, tooltipBorder, gridStroke } = useChartTheme();
 68→
 69→	const seriesKeys = useMemo(() => {
 70→		if (data.length === 0) return [];
 71→		const keys = new Set<string>();
 72→		for (const item of data) {
 73→			keys.add(item.dimension);
 74→		}
 75→		return Array.from(keys).sort();
 76→	}, [data]);
 77→
 78→	const chartData = useMemo(() => {
 79→		if (data.length === 0) return [];
 80→
 81→		const allDates = Array.from(new Set(data.map((item) => item.date))).sort();
 82→		if (allDates.length === 0) return [];
 83→
 84→		const minDate = new Date(allDates[0]);
 85→		const maxDate = new Date(allDates[allDates.length - 1]);
 86→		const dateRange: string[] = [];
 87→
 88→		for (let d = new Date(minDate); d <= maxDate; d.setDate(d.getDate() + 1)) {
 89→			dateRange.push(d.toISOString().split("T")[0]);
 90→		}
 91→
 92→		const dateMap = new Map<string, Record<string, unknown>>();
 93→
 94→		for (const dateKey of dateRange) {
 95→			const dateData: Record<string, unknown> = {
 96→				date: dateKey,
 97→				displayDate: new Date(dateKey).toLocaleDateString("en-US", {
 98→					month: "short",
 99→					day: "numeric",
100→				}),
101→			};
102→			for (const key of seriesKeys) {
103→				dateData[key] = 0;
104→			}
105→			dateMap.set(dateKey, dateData);
106→		}
107→
108→		for (const item of data) {
109→			const dateKey = item.date;
110→			const dateData = dateMap.get(dateKey);
111→			if (dateData) {
112→				dateData[item.dimension] = item[metric];
113→			}
114→		}
115→
116→		return Array.from(dateMap.values()).sort((a, b) =>
117→			(a.date as string).localeCompare(b.date as string),
118→		);
119→	}, [data, metric, seriesKeys]);
120→
121→	const getDisplayName = (key: string): string => {
122→		if (splitBy === "user_id" && userMap) {
123→			return userMap.get(key) || `${key.substring(0, 12)}...`;
124→		}
125→		return key;
126→	};
127→
128→	return (
129→		<div className="space-y-4">
130→			<div className="flex flex-wrap items-center justify-between gap-4">
131→				<div className="flex items-center gap-2">
132→					<label
133→						htmlFor="error-metric-select"
134→						className="text-sm font-medium text-muted"
135→					>
136→						Metric:
137→					</label>
138→					<select
139→						id="error-metric-select"
140→						value={metric}
141→						onChange={(e) => onMetricChange(e.target.value as typeof metric)}
142→						className="px-3 py-2 border border-border rounded-md text-sm bg-input focus:outline-none focus:ring-2 focus:ring-accent w-56"
143→					>
144→						{Object.entries(METRIC_LABELS).map(([key, label]) => (
145→							<option key={key} value={key}>
146→								{label}
147→							</option>
148→						))}
149→					</select>
150→				</div>
151→
152→				<div className="flex items-center gap-2">
153→					<label
154→						htmlFor="error-split-select"
155→						className="text-sm font-medium text-muted"
156→					>
157→						Split:
158→					</label>
159→					<select
160→						id="error-split-select"
161→						value={splitBy}
162→						onChange={(e) => onSplitByChange(e.target.value as typeof splitBy)}
163→						className="px-3 py-2 border border-border rounded-md text-sm bg-input focus:outline-none focus:ring-2 focus:ring-accent w-40"
164→					>
165→						{Object.entries(SPLIT_LABELS).map(([key, label]) => (
166→							<option key={key} value={key}>
167→								{label}
168→							</option>
169→						))}
170→					</select>
171→				</div>
172→			</div>
173→
174→			<ResponsiveContainer width="100%" height={400}>
175→				{metric === "total_errors" ? (
176→					<AreaChart
177→						data={chartData}
178→						margin={{ top: 10, right: 30, left: 0, bottom: 0 }}
179→					>
180→						<CartesianGrid strokeDasharray="3 3" stroke={gridStroke} />
181→						<XAxis
182→							dataKey="displayDate"
183→							tick={{ fontSize: 12 }}
184→							angle={-45}
185→							textAnchor="end"
186→							height={80}
187→						/>
188→						<YAxis tick={{ fontSize: 12 }} />
189→						<Tooltip
190→							contentStyle={{
191→								backgroundColor: tooltipBg,
192→								border: `1px solid ${tooltipBorder}`,
193→								borderRadius: "8px",
194→								padding: "12px",
195→							}}
196→							formatter={(value, name) => {
197→								const displayName = name ? getDisplayName(String(name)) : "";
198→								return [((value as number) ?? 0).toLocaleString(), displayName];
199→							}}
200→							labelFormatter={(label) => `Date: ${label}`}
201→						/>
202→						<Legend
203→							formatter={(value) => getDisplayName(value)}
204→							wrapperStyle={{ fontSize: "12px" }}
205→						/>
206→						{seriesKeys.map((key, index) => (
207→							<Area
208→								key={key}
209→								type="monotone"
210→								dataKey={key}
211→								name={key}
212→								stackId="1"
213→								stroke={COLORS[index % COLORS.length]}
214→								fill={COLORS[index % COLORS.length]}
215→								fillOpacity={0.6}
216→							/>
217→						))}
218→					</AreaChart>
219→				) : (
220→					<LineChart
221→						data={chartData}
222→						margin={{ top: 10, right: 30, left: 0, bottom: 0 }}
223→					>
224→						<CartesianGrid strokeDasharray="3 3" stroke={gridStroke} />
225→						<XAxis
226→							dataKey="displayDate"
227→							tick={{ fontSize: 12 }}
228→							angle={-45}
229→							textAnchor="end"
230→							height={80}
231→						/>
232→						<YAxis tick={{ fontSize: 12 }} />
233→						<Tooltip
234→							contentStyle={{
235→								backgroundColor: tooltipBg,
236→								border: `1px solid ${tooltipBorder}`,
237→								borderRadius: "8px",
238→								padding: "12px",
239→							}}
240→							formatter={(value, name) => {
241→								const displayName = name ? getDisplayName(String(name)) : "";
242→								return [((value as number) ?? 0).toFixed(2), displayName];
243→							}}
244→							labelFormatter={(label) => `Date: ${label}`}
245→						/>
246→						<Legend
