  1→import { useMemo, useState } from "react";
  2→import {
  3→	Area,
  4→	AreaChart,
  5→	CartesianGrid,
  6→	Legend,
  7→	ResponsiveContainer,
  8→	Tooltip,
  9→	XAxis,
 10→	YAxis,
 11→} from "recharts";
 12→import { useChartTheme } from "@/hooks/useChartTheme";
 13→import {
 14→	Select,
 15→	SelectContent,
 16→	SelectItem,
 17→	SelectTrigger,
 18→	SelectValue,
 19→} from "@/components/ui/select";
 20→import { Switch } from "@/components/ui/switch";
 21→
 22→interface LearningsTrendChartProps {
 23→	data: Record<string, string | number>[];
 24→	splitBy: "user_id" | "repository";
 25→	onSplitByChange: (splitBy: "user_id" | "repository") => void;
 26→	userMap?: Map<string, string>;
 27→}
 28→
 29→const COLORS = [
 30→	"#3b82f6",
 31→	"#10b981",
 32→	"#f59e0b",
 33→	"#8b5cf6",
 34→	"#ef4444",
 35→	"#06b6d4",
 36→	"#ec4899",
 37→	"#14b8a6",
 38→	"#f97316",
 39→	"#6366f1",
 40→];
 41→
 42→export function LearningsTrendChart({
 43→	data,
 44→	splitBy,
 45→	onSplitByChange,
 46→	userMap,
 47→}: LearningsTrendChartProps) {
 48→	const { tooltipBg, tooltipBorder, gridStroke } = useChartTheme();
 49→	const [isCumulative, setIsCumulative] = useState(true);
 50→
 51→	const seriesKeys = useMemo(() => {
 52→		if (data.length === 0) return [];
 53→		const keys = new Set<string>();
 54→		for (const item of data) {
 55→			for (const key of Object.keys(item)) {
 56→				if (key !== "date") {
 57→					keys.add(key);
 58→				}
 59→			}
 60→		}
 61→		return Array.from(keys).sort();
 62→	}, [data]);
 63→
 64→	const chartData = useMemo(() => {
 65→		if (!isCumulative) {
 66→			return data.map((item) => ({
 67→				...item,
 68→				displayDate: new Date(item.date as string).toLocaleDateString("en-US", {
 69→					month: "short",
 70→					day: "numeric",
 71→				}),
 72→			}));
 73→		}
 74→
 75→		const cumulativeData = [];
 76→		const runningTotals: Record<string, number> = {};
 77→
 78→		for (const key of seriesKeys) {
 79→			runningTotals[key] = 0;
 80→		}
 81→
 82→		for (const item of data) {
 83→			const cumulativeItem: Record<string, unknown> = {
 84→				date: item.date,
 85→				displayDate: new Date(item.date as string).toLocaleDateString("en-US", {
 86→					month: "short",
 87→					day: "numeric",
 88→				}),
 89→			};
 90→
 91→			for (const key of seriesKeys) {
 92→				runningTotals[key] += (item[key] as number) || 0;
 93→				cumulativeItem[key] = runningTotals[key];
 94→			}
 95→
 96→			cumulativeData.push(cumulativeItem);
 97→		}
 98→
 99→		return cumulativeData;
100→	}, [data, isCumulative, seriesKeys]);
101→
102→	const getDisplayName = (key: string): string => {
103→		if (splitBy === "user_id" && userMap) {
104→			return userMap.get(key) || `${key.substring(0, 12)}...`;
105→		}
106→		return key;
107→	};
108→
109→	return (
110→		<div className="space-y-4">
111→			<div className="flex flex-wrap items-center justify-end gap-4">
112→				<div className="flex items-center gap-2">
113→					<select
114→						value={splitBy}
115→						onChange={(e) =>
116→							onSplitByChange(e.target.value as "user_id" | "repository")
117→						}
118→						className="px-3 py-2 border border-border rounded-md text-sm bg-input focus:outline-none focus:ring-2 focus:ring-accent w-40"
119→					>
120→						<option value="user_id">by Developer</option>
121→						<option value="repository">by Repository</option>
122→					</select>
123→				</div>
124→
125→				<div className="flex items-center gap-2">
126→					<label
127→						htmlFor="cumulative-toggle"
128→						className="text-sm font-medium text-muted cursor-pointer"
129→					>
130→						Cumulative
131→					</label>
132→					<button
133→						type="button"
134→						id="cumulative-toggle"
135→						role="switch"
136→						aria-checked={isCumulative}
137→						onClick={() => setIsCumulative(!isCumulative)}
138→						className={`
139→							relative inline-flex h-6 w-11 items-center rounded-full transition-colors
140→							${isCumulative ? "bg-accent" : "bg-border"}
141→						`}
142→					>
143→						<span
144→							className={`
145→								inline-block h-4 w-4 transform rounded-full bg-input transition-transform
146→								${isCumulative ? "translate-x-6" : "translate-x-1"}
147→							`}
148→						/>
149→					</button>
150→				</div>
151→			</div>
152→
153→			<ResponsiveContainer width="100%" height={400}>
154→				<AreaChart
155→					data={chartData}
156→					margin={{ top: 10, right: 30, left: 0, bottom: 0 }}
157→				>
158→					<CartesianGrid strokeDasharray="3 3" stroke={gridStroke} />
159→					<XAxis
160→						dataKey="displayDate"
161→						tick={{ fontSize: 12 }}
162→						angle={-45}
163→						textAnchor="end"
164→						height={80}
165→					/>
166→					<YAxis tick={{ fontSize: 12 }} />
167→					<Tooltip
168→						contentStyle={{
169→							backgroundColor: tooltipBg,
170→							border: `1px solid ${tooltipBorder}`,
171→							borderRadius: "8px",
172→							padding: "12px",
173→						}}
174→						formatter={(value, name) => {
175→							const displayName = name ? getDisplayName(String(name)) : "";
176→							return [((value as number) ?? 0).toLocaleString(), displayName];
177→						}}
178→						labelFormatter={(label) => `Date: ${label}`}
179→					/>
180→					<Legend
181→						formatter={(value) => getDisplayName(value)}
182→						wrapperStyle={{ fontSize: "12px" }}
183→					/>
184→					{seriesKeys.map((key, index) => (
185→						<Area
186→							key={key}
187→							type="monotone"
188→							dataKey={key}
189→							name={key}
190→							stackId="1"
191→							stroke={COLORS[index % COLORS.length]}
192→							fill={COLORS[index % COLORS.length]}
193→							fillOpacity={0.6}
194→						/>
195→					))}
196→				</AreaChart>
197→			</ResponsiveContainer>
198→
199→			{seriesKeys.length === 0 && (
200→				<div className="text-center text-sm text-muted py-4">
201→					No data available for the selected time period
202→				</div>
203→			)}
204→		</div>
205→	);
206→}
