  1→import type { ErrorTrendDataPoint } from "@rudel/api-routes";
  2→import { useMemo } from "react";
  3→import {
  4→	Area,
  5→	AreaChart,
  6→	CartesianGrid,
  7→	Legend,
  8→	Line,
  9→	LineChart,
 10→	ResponsiveContainer,
 11→	Tooltip,
 12→	XAxis,
 13→	YAxis,
 14→} from "recharts";
 15→import { useChartTheme } from "@/hooks/useChartTheme";
 16→import {
 17→	Select,
 18→	SelectContent,
 19→	SelectItem,
 20→	SelectTrigger,
 21→	SelectValue,
