 23→
 24→interface ErrorTrendChartProps {
 25→	data: ErrorTrendDataPoint[];
 26→	metric:
 27→		| "avg_errors_per_interaction"
 28→		| "avg_errors_per_session"
 29→		| "total_errors";
 30→	splitBy: "repository" | "user_id" | "model";
 31→	onMetricChange: (
 32→		metric:
 33→			| "avg_errors_per_interaction"
 34→			| "avg_errors_per_session"
 35→			| "total_errors",
 36→	) => void;
 37→	onSplitByChange: (splitBy: "repository" | "user_id" | "model") => void;
 38→	userMap?: Map<string, string>;
 39→}
 40→
 41→const COLORS = [
 42→	"#ef4444",
 43→	"#f59e0b",
 44→	"#10b981",
 45→	"#3b82f6",
 46→	"#8b5cf6",
 47→	"#ec4899",
 48→	"#06b6d4",
 49→	"#14b8a6",
 50→	"#f97316",
 51→	"#6366f1",
 52→];
 53→
 54→const METRIC_LABELS: Record<string, string> = {
 55→	avg_errors_per_interaction: "Avg Errors per Interaction",
 56→	avg_errors_per_session: "Avg Errors per Session",
 57→	total_errors: "Total Errors",
 58→};
 59→
 60→const SPLIT_LABELS: Record<string, string> = {
 61→	repository: "by Repository",
 62→	user_id: "by Developer",
 63→	model: "by Model",
 64→};
 65→
 66→export function ErrorTrendChart({
 67→	data,
 68→	metric,
 69→	splitBy,
 70→	onMetricChange,
 71→	onSplitByChange,
 72→	userMap,
 73→}: ErrorTrendChartProps) {
 74→	const { tooltipBg, tooltipBorder, gridStroke } = useChartTheme();
 75→
 76→	const seriesKeys = useMemo(() => {
 77→		if (data.length === 0) return [];
 78→		const keys = new Set<string>();
 79→		for (const item of data) {
 80→			keys.add(item.dimension);
 81→		}
 82→		return Array.from(keys).sort();
 83→	}, [data]);
 84→
 85→	const chartData = useMemo(() => {
 86→		if (data.length === 0) return [];
 87→
 88→		const allDates = Array.from(new Set(data.map((item) => item.date))).sort();
 89→		if (allDates.length === 0) return [];
 90→
 91→		const minDate = new Date(allDates[0]);
 92→		const maxDate = new Date(allDates[allDates.length - 1]);
 93→		const dateRange: string[] = [];
 94→
 95→		for (let d = new Date(minDate); d <= maxDate; d.setDate(d.getDate() + 1)) {
 96→			dateRange.push(d.toISOString().split("T")[0]);
 97→		}
 98→
 99→		const dateMap = new Map<string, Record<string, unknown>>();
100→
101→		for (const dateKey of dateRange) {
102→			const dateData: Record<string, unknown> = {
103→				date: dateKey,
104→				displayDate: new Date(dateKey).toLocaleDateString("en-US", {
105→					month: "short",
106→					day: "numeric",
107→				}),
108→			};
109→			for (const key of seriesKeys) {
110→				dateData[key] = 0;
111→			}
112→			dateMap.set(dateKey, dateData);
113→		}
114→
115→		for (const item of data) {
116→			const dateKey = item.date;
117→			const dateData = dateMap.get(dateKey);
118→			if (dateData) {
119→				dateData[item.dimension] = item[metric];
120→			}
121→		}
122→
123→		return Array.from(dateMap.values()).sort((a, b) =>
124→			(a.date as string).localeCompare(b.date as string),
125→		);
126→	}, [data, metric, seriesKeys]);
127→
128→	const getDisplayName = (key: string): string => {
129→		if (splitBy === "user_id" && userMap) {
130→			return userMap.get(key) || `${key.substring(0, 12)}...`;
131→		}
132→		return key;
133→	};
134→
135→	return (
136→		<div className="space-y-4">
137→			<div className="flex flex-wrap items-center justify-between gap-4">
138→				<div className="flex items-center gap-2">
139→					<label
140→						htmlFor="error-metric-select"
141→						className="text-sm font-medium text-muted"
142→					>
143→						Metric:
144→					</label>
145→					<select
146→						id="error-metric-select"
147→						value={metric}
148→						onChange={(e) => onMetricChange(e.target.value as typeof metric)}
149→						className="px-3 py-2 border border-border rounded-md text-sm bg-input focus:outline-none focus:ring-2 focus:ring-accent w-56"
150→					>
151→						{Object.entries(METRIC_LABELS).map(([key, label]) => (
152→							<option key={key} value={key}>
153→								{label}
154→							</option>
155→						))}
156→					</select>
157→				</div>
158→
159→				<div className="flex items-center gap-2">
160→					<label
161→						htmlFor="error-split-select"
162→						className="text-sm font-medium text-muted"
163→					>
164→						Split:
165→					</label>
166→					<select
167→						id="error-split-select"
168→						value={splitBy}
169→						onChange={(e) => onSplitByChange(e.target.value as typeof splitBy)}
170→						className="px-3 py-2 border border-border rounded-md text-sm bg-input focus:outline-none focus:ring-2 focus:ring-accent w-40"
171→					>
172→						{Object.entries(SPLIT_LABELS).map(([key, label]) => (
173→							<option key={key} value={key}>
174→								{label}
175→							</option>
176→						))}
177→					</select>
178→				</div>
179→			</div>
180→
181→			<ResponsiveContainer width="100%" height={400}>
182→				{metric === "total_errors" ? (
183→					<AreaChart
184→						data={chartData}
185→						margin={{ top: 10, right: 30, left: 0, bottom: 0 }}
186→					>
187→						<CartesianGrid strokeDasharray="3 3" stroke={gridStroke} />
188→						<XAxis
189→							dataKey="displayDate"
190→							tick={{ fontSize: 12 }}
191→							angle={-45}
192→							textAnchor="end"
193→							height={80}
194→						/>
195→						<YAxis tick={{ fontSize: 12 }} />
196→						<Tooltip
197→							contentStyle={{
198→								backgroundColor: tooltipBg,
199→								border: `1px solid ${tooltipBorder}`,
200→								borderRadius: "8px",
201→								padding: "12px",
202→							}}
203→							formatter={(value, name) => {
204→								const displayName = name ? getDisplayName(String(name)) : "";
205→								return [((value as number) ?? 0).toLocaleString(), displayName];
206→							}}
207→							labelFormatter={(label) => `Date: ${label}`}
208→						/>
209→						<Legend
210→							formatter={(value) => getDisplayName(value)}
211→							wrapperStyle={{ fontSize: "12px" }}
212→						/>
213→						{seriesKeys.map((key, index) => (
214→							<Area
215→								key={key}
216→								type="monotone"
217→								dataKey={key}
218→								name={key}
219→								stackId="1"
220→								stroke={COLORS[index % COLORS.length]}
221→								fill={COLORS[index % COLORS.length]}
222→								fillOpacity={0.6}
223→							/>
224→						))}
225→					</AreaChart>
226→				) : (
227→					<LineChart
228→						data={chartData}
229→						margin={{ top: 10, right: 30, left: 0, bottom: 0 }}
230→					>
231→						<CartesianGrid strokeDasharray="3 3" stroke={gridStroke} />
232→						<XAxis
233→							dataKey="displayDate"
234→							tick={{ fontSize: 12 }}
235→							angle={-45}
236→							textAnchor="end"
237→							height={80}
238→						/>
239→						<YAxis tick={{ fontSize: 12 }} />
240→						<Tooltip
241→							contentStyle={{
242→								backgroundColor: tooltipBg,
243→								border: `1px solid ${tooltipBorder}`,
244→								borderRadius: "8px",
245→								padding: "12px",
246→							}}
247→							formatter={(value, name) => {
248→								const displayName = name ? getDisplayName(String(name)) : "";
249→								return [((value as number) ?? 0).toFixed(2), displayName];
250→							}}
251→							labelFormatter={(label) => `Date: ${label}`}
252→						/>
253→						<Legend
254→							formatter={(value) => getDisplayName(value)}
255→							wrapperStyle={{ fontSize: "12px" }}
256→						/>
257→						{seriesKeys.map((key, index) => (
258→							<Line
259→								key={key}
260→								type="monotone"
261→								dataKey={key}
262→								name={key}
263→								stroke={COLORS[index % COLORS.length]}
264→								strokeWidth={2}
265→								dot={{ r: 4 }}
266→								activeDot={{ r: 6 }}
267→								connectNulls={false}
268→							/>
269→						))}
270→					</LineChart>
271→				)}
272→			</ResponsiveContainer>
273→
274→			{seriesKeys.length === 0 && (
275→				<div className="text-center text-sm text-muted py-4">
276→					No error data available for the selected time period
277→				</div>
278→			)}
279→		</div>
280→	);
281→}
